    readFileSync: vi.fn(actual.readFileSync),
  };
});

function makeRunLog(overrides?: Partial<RunLog>): RunLog {
  return {
    version: 1,
    runId: "test-run-id-1234",
    startTime: "2026-03-23T10:00:00.000Z",
    endTime: "2026-03-23T10:05:00.000Z",
    config: {
      phases: ["spec", "exec", "qa"],
      sequential: false,
      qualityLoop: false,
      maxIterations: 3,
    },
    issues: [
      {
        issueNumber: 100,
        title: "Test issue 1",
        labels: ["enhancement"],
        status: "success",
        phases: [
          {
            phase: "spec",
            issueNumber: 100,
            startTime: "2026-03-23T10:00:00.000Z",
            endTime: "2026-03-23T10:01:00.000Z",
            durationSeconds: 60,
            status: "success",
          },
          {
            phase: "exec",
            issueNumber: 100,
            startTime: "2026-03-23T10:01:00.000Z",
            endTime: "2026-03-23T10:03:00.000Z",
            durationSeconds: 120,
            status: "success",
          },
          {
            phase: "qa",
            issueNumber: 100,
            startTime: "2026-03-23T10:03:00.000Z",
            endTime: "2026-03-23T10:04:00.000Z",
            durationSeconds: 60,
            status: "success",
            verdict: "READY_FOR_MERGE",
          },
        ],
        totalDurationSeconds: 240,
      },
      {
        issueNumber: 200,
        title: "Test issue 2",
        labels: ["bug"],
        status: "failure",
        phases: [
          {
            phase: "spec",
            issueNumber: 200,
            startTime: "2026-03-23T10:00:00.000Z",
            endTime: "2026-03-23T10:01:00.000Z",
            durationSeconds: 60,
            status: "success",
          },
          {
            phase: "exec",
            issueNumber: 200,
            startTime: "2026-03-23T10:01:00.000Z",
            endTime: "2026-03-23T10:02:30.000Z",
            durationSeconds: 90,
            status: "failure",
            error: "Build failed",
          },
        ],
        totalDurationSeconds: 150,
      },
    ],
    summary: {
      totalIssues: 2,
      passed: 1,
      failed: 1,
      totalDurationSeconds: 300,
    },
    ...overrides,
  };
